// // This module decrements the 4-bit counter on each rising edge of the clock when the decrement signal is high and resets it to 7 when the clear signal is asserted.
module top_module(output reg [3: 0] A, input incr, clear, clock);always @ (posedge clock)  
    if (clear) 	A <= 0; else if (incr) A <= A + 1;endmodule
